patch:
--- a/adder.v
+++ b/adder.v
@@ -11,7 +11,7 @@ module top;
   wire [7:0] result;

   adder_4bit add_inst (
-    .input_a(a),
+    .in_a(a),
     .in_b(b),
     .sum(result)
   );

before_code:
module adder_4bit(
  input [3:0] in_a,
  input [3:0] in_b,
  output [4:0] sum
);
  assign sum = in_a + in_b;
endmodule

module top;
  reg [3:0] a, b;
  wire [7:0] result;

  adder_4bit add_inst (
    .input_a(a),
    .in_b(b),
    .sum(result)
  );
endmodule

after_code:
module adder_4bit(
  input [3:0] in_a,
  input [3:0] in_b,
  output [4:0] sum
);
  assign sum = in_a + in_b;
endmodule

module top;
  reg [3:0] a, b;
  wire [7:0] result;

  adder_4bit add_inst (
    .in_a(a),
    .in_b(b),
    .sum(result)
  );
endmodule
